import { useEffect, useState } from "react";
import "../styles/style.scss";

export default function Header() {
  const [language, setLanguage] = useState("pt");
  const [darkMode, setDarkMode] = useState(false);

  function handleLanguageChange(lang) {
    setLanguage(lang);

    localStorage.setItem("language", lang);
  }

  useEffect(() => {
    // Verifica se existe um idioma salvo no localStorage
    const savedLanguage = localStorage.getItem("language");
    if (savedLanguage) {
      setLanguage(savedLanguage); // Aplica o idioma salvo
    }
  }, []);

  useEffect(() => {
    // Altera a exibição de conteúdo com base no idioma selecionado
    const elements = document.querySelectorAll("[data-lang]");
    elements.forEach((element) => {
      if (element.getAttribute("data-lang") === language) {
        element.style.display = "block"; // Exibe o conteúdo no idioma selecionado
      } else {
        element.style.display = "none"; // Esconde o conteúdo no outro idioma
      }
    });
  }, [language]);

  // Função para habilitar o dark mode
  const enableDarkMode = () => {
    document.body.classList.add("darkmode");
    setDarkMode(true);
    localStorage.setItem("darkMode", "enabled");
  };

  // Função para desabilitar o dark mode
  const disableDarkMode = () => {
    document.body.classList.remove("darkmode");
    setDarkMode(false);
    localStorage.setItem("darkMode", "disabled");
  };

  // Verifica se o darkMode está habilitado no localStorage quando o componente for montado
  useEffect(() => {
    const savedDarkMode = localStorage.getItem("darkMode");
    if (savedDarkMode === "enabled") {
      enableDarkMode();
    } else {
      disableDarkMode();
    }
  }, []);

  // Função para alternar entre os modos
  const handleToggle = () => {
    if (darkMode) {
      disableDarkMode();
    } else {
      enableDarkMode();
    }
  };

  return (
    <header>
      <nav>
        <div className="logo">Portfolio.</div>
        <div className="links">
          <ul className="nav-bar">
            <input type="checkbox" id="check" />
            <span className="menu">
              <li>
                <a href="#about-me" data-lang="pt">
                  Sobre mim
                </a>
                <a href="#about-me" data-lang="en" style={{ display: "none" }}>
                  About me
                </a>
              </li>
              <li>
                <a href="#skills" data-lang="pt">
                  Competências
                </a>
                <a href="#skills" data-lang="en" style={{ display: "none" }}>
                  Skills
                </a>
              </li>
              <li>
                <a href="#experience" data-lang="pt">
                  Qualificações
                </a>
                <a
                  href="#experience"
                  data-lang="en"
                  style={{ display: "none" }}
                >
                  Qualifications
                </a>
              </li>
              <li>
                <a href="#projects" data-lang="pt">
                  Projetos
                </a>
                <a href="#projects" data-lang="en" style={{ display: "none" }}>
                  Projects
                </a>
              </li>

              <label htmlFor="check" className="close-menu">
                <i className="fas fa-times"></i>
              </label>

              <div className="icons">
                <button
                  onClick={(e) => {
                    e.preventDefault();
                    handleLanguageChange("pt");
                  }}
                  className={`lang-toggle ${language === "pt" ? "active" : ""}`}
                >
                  PT
                </button>
                <span className="language-toggle">|</span>
                <button
                  onClick={(e) => {
                    e.preventDefault();
                    handleLanguageChange("en");
                  }}
                  className={`lang-toggle ${language === "en" ? "active" : ""}`}
                >
                  EN
                </button>

                <button
                  id="dark-mode-toggle"
                  className="dark-mode-toggle"
                  onClick={handleToggle}
                >
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    viewBox="0 0 512 512"
                    id="dark-mode-icon-light"
                    style={{ display: darkMode ? "none" : "block" }}
                  >
                    <path
                      fill="currentColor"
                      d="M283.2 512c79 0 151.1-35.9 198.9-94.8 7.1-8.7-.6-21.4-11.6-19.4-124.2 23.7-238.3-71.6-238.3-197 0-72.2 38.7-138.6 101.5-174.4 9.7-5.5 7.3-20.2-3.8-22.2A258.2 258.2 0 0 0 283.2 0c-141.3 0-256 114.5-256 256 0 141.3 114.5 256 256 256z"
                      transform="translate(-8 -8)"
                    />
                  </svg>
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    viewBox="0 0 512 512"
                    id="dark-mode-icon-dark"
                    style={{ display: darkMode ? "block" : "none" }}
                  >
                    <path
                      fill="currentColor"
                      d="M256 160c-52.9 0-96 43.1-96 96s43.1 96 96 96 96-43.1 96-96-43.1-96-96-96zm246.4 80.5l-94.7-47.3 33.5-100.4c4.5-13.6-8.4-26.5-21.9-21.9l-100.4 33.5-47.4-94.8c-6.4-12.8-24.6-12.8-31 0l-47.3 94.7L92.7 70.8c-13.6-4.5-26.5 8.4-21.9 21.9l33.5 100.4-94.7 47.4c-12.8 6.4-12.8 24.6 0 31l94.7 47.3-33.5 100.5c-4.5 13.6 8.4 26.5 21.9 21.9l100.4-33.5 47.3 94.7c6.4 12.8 24.6 12.8 31 0l47.3-94.7 100.4 33.5c13.6 4.5 26.5-8.4 21.9-21.9l-33.5-100.4 94.7-47.3c13-6.5 13-24.7 .2-31.1zm-155.9 106c-49.9 49.9-131.1 49.9-181 0-49.9-49.9-49.9-131.1 0-181 49.9-49.9 131.1-49.9 181 0 49.9 49.9 49.9 131.1 0 181z"
                    />
                  </svg>
                </button>
              </div>
            </span>
          </ul>
        </div>
      </nav>
    </header>
  );
}
